interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  amulet: 60,
};

const quotePremium = (step: QuoteStep): number => {
  const policyBase = step.items.reduce(
    (sum, item) => sum + BASE_PREMIUM[item.type],
    0,
  );
  const firstInsurance = policyBase * 0.1;
  return Math.ceil(policyBase + firstInsurance + 5);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  return {
    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
  };
};

