import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge / simplest cases ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Single main item base premiums (+ fee, no other modifiers; newcomer 0y first insurance) ---
  // Note: simplest isolated base premium tests use a long-standing customer's follow-up to neutralise,
  // but we start with raw single-item quotes where only fee + first-insurance apply per spec.

  // --- Base premium per item type (isolated, expressed via newcomer single quote) ---
  it("single amulet (newcomer) → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("single staff base premium 80 G");
  it.todo("single potion base premium 40 G");
  it.todo("single sword base premium 100 G");

  // --- Components and building blocks (base premium only) ---
  it.todo("2 runes → 50 G base premium");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Premium modifiers (item-specific) ---
  it.todo("cursed sword (steel, ench 3), newcomer → premium 165 G");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → curse adds 50 G (50% of sword base, not policy total) → 210 G before fee");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → loyalty discount applies");

  // --- Rounding ---
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // --- Integration examples (premium) ---
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3y → premium 160 G");

  // --- Claims: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100 (full minus deductible; no special clause)");

  // --- Claims: enchantment / dragon clauses ---
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both clauses, 50% wins, then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment 50%, then deductible)");

  // --- Claims: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // --- Claims: multiple items same type ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000; two sword damages each own deductible");
  it.todo("more damage entries of a type than policy covers → CLI rejects (non-zero exit)");

  // --- Claims: cap ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium 165 → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount does not affect sum)");
  it.todo("two successive 1500 claims on sword: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");

  // --- Claims: rounding ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Error cases ---
  it.todo("quote with unknown item type → non-zero exit, error to stderr, no results on stdout");
  it.todo("claim references item not in policy → non-zero exit, error to stderr");
  it.todo("claim damage entry with amount -200 → non-zero exit, error to stderr");
});

