  it.todo("sword + 3 runes block → insurance sum 1750 (block discount does not affect sum)");
  it.todo("two successive 1500 claims on sword: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");

  // --- Claims: rounding ---
