const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PREMIUM = 60;

const runesBasePremium = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_PREMIUM : runeCount * BASE_PREMIUM.rune;

const policyBasePremium = (items: { type: string }[]): number => {
  const runeCount = items.filter((item) => item.type === "rune").length;
  const nonRuneBase = items
    .filter((item) => item.type !== "rune")
    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return runesBasePremium(runeCount) + nonRuneBase;
};

const quotePremium = (step: QuoteStep): number => {
  const policyBase = policyBasePremium(step.items);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  return {
    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
  };
};

