interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

const COMPONENT_TYPES = ["rune", "moonstone"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);

const typeBasePremium = (type: string, count: number): number =>
  isComponent(type) && count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * BASE_PREMIUM[type];

const countByType = (items: { type: string }[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const policyBasePremium = (items: { type: string }[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + typeBasePremium(type, count),
    0,
  );

const quotePremium = (step: QuoteStep): number => {
  const policyBase = policyBasePremium(step.items);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  return {
    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
  };
};

