  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3y → premium 160 G");

  // --- Claims: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100 (full minus deductible; no special clause)");

  // --- Claims: enchantment / dragon clauses ---
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both clauses, 50% wins, then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment 50%, then deductible)");

  // --- Claims: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // --- Claims: multiple items same type ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000; two sword damages each own deductible");
  it.todo("more damage entries of a type than policy covers → CLI rejects (non-zero exit)");

  // --- Claims: cap ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium 165 → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount does not affect sum)");
  it.todo("two successive 1500 claims on sword: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");

  // --- Claims: rounding ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Error cases ---
  it.todo("quote with unknown item type → non-zero exit, error to stderr, no results on stdout");
  it.todo("claim references item not in policy → non-zero exit, error to stderr");
  it.todo("claim damage entry with amount -200 → non-zero exit, error to stderr");
});

