interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FOLLOWUP_DISCOUNT_RATE = 0.15;

const COMPONENT_TYPES = ["rune", "moonstone"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);

const typeBasePremium = (type: string, count: number): number =>
  isComponent(type) && count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * BASE_PREMIUM[type];

const CURSE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_RATE = 0.3;

const surchargeForItem = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const curse = item.cursed ? CURSE_RATE * base : 0;
  const highEnchantment =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? HIGH_ENCHANTMENT_RATE * base
      : 0;
  return curse + highEnchantment;
};

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + surchargeForItem(item), 0);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const policyBasePremium = (items: Item[]): number =>
  [...countByType(items)].reduce(
    (total, [type, count]) => total + typeBasePremium(type, count),
    0,
  );

const isLoyal = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;

const policyModifierRate = (customer: Customer): number =>
  FIRST_INSURANCE_RATE - (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0);

const quotePremium = (step: QuoteStep, customer: Customer): number => {
  const policyBase = policyBasePremium(step.items);
  const policyModifiers = policyBase * policyModifierRate(customer);
  return Math.ceil(
    policyBase + itemSurcharges(step.items) + policyModifiers + PROCESSING_FEE,
  );
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  return {
    results: scenario.steps.map((step) => ({
      premium: quotePremium(step, scenario.customer),
    })),
  };
};

