const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  const cap = 2 * insuranceSum(policyItems);
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
    0,
  );
  return { payout: Math.floor(payout), remainingCap: cap - payout };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const policies: Item[][] = [];
  let quoteCount = 0;
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push({
        premium: quotePremium(step, scenario.customer, quoteCount > 0),
      });
      policies.push(step.items);
