  const counts = new Map<string, number>();
  for (const damage of damages) {
    counts.set(damage.itemType, (counts.get(damage.itemType) ?? 0) + 1);
  }
  return counts;
};

const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
  const insuredCounts = countByType(policyItems);
  for (const [itemType, count] of damageCountByType(damages)) {
    if (count > (insuredCounts.get(itemType) ?? 0)) {
      throw new Error(
        `Claim rejected: ${count} ${itemType} damages exceed insured count`,
      );
    }
  }
};

const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  validateDamages(step.incident.damages, policyItems);
  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage, policyItems),
    0,
  );
  return { payout: Math.floor(payout), remainingCap: cap - payout };
};

