84	  const curse = item.cursed ? CURSE_RATE * base : 0;
85	  const highEnchantment =
86	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
87	      ? HIGH_ENCHANTMENT_RATE * base
88	      : 0;
89	  return curse + highEnchantment;
90	};
91	
92	const itemSurcharges = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
94	
95	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
96	  const counts = new Map<string, number>();
97	  for (const item of items) {
98	    const key = keyOf(item);
99	    counts.set(key, (counts.get(key) ?? 0) + 1);
100	  }
101	  return counts;
102	};
103	
104	const countByType = (items: Item[]): Map<string, number> =>
105	  countBy(items, (item) => item.type);
106	
107	const policyBasePremium = (items: Item[]): number =>
108	  [...countByType(items)].reduce(
109	    (total, [type, count]) => total + typeBasePremium(type, count),
110	    0,
111	  );
112	
113	const isLoyal = (customer: Customer): boolean =>
114	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
115	
116	const policyModifierRate = (customer: Customer, isFollowup: boolean): number =>
117	  FIRST_INSURANCE_RATE -
118	  (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0) -
119	  (isFollowup ? FOLLOWUP_DISCOUNT_RATE : 0);
120	
121	const isKnownType = (type: string): boolean => type in BASE_PREMIUM;
122	
123	const validateItems = (items: Item[]): void => {
124	  for (const item of items) {
125	    if (!isKnownType(item.type)) {
126	      throw new Error(`Unknown item type: ${item.type}`);
127	    }
128	  }
129	};
130	
131	const quotePremium = (
132	  items: Item[],
133	  customer: Customer,
134	  isFollowup: boolean,
135	): number => {
136	  validateItems(items);
137	  const policyBase = policyBasePremium(items);
138	  const policyModifierAmount =
139	    policyBase * policyModifierRate(customer, isFollowup);
140	  return Math.ceil(
141	    policyBase +
142	      itemSurcharges(items) +
143	      policyModifierAmount +
144	      PROCESSING_FEE,
145	  );
146	};
147	
148	const insuranceSum = (items: Item[]): number =>
149	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
150	
151	const qualifiesForHalfReimbursement = (item: Item | undefined): boolean =>
152	  (item?.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD;
153	
154	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
155	  qualifiesForHalfReimbursement(item)
156	    ? HALF_REIMBURSEMENT_RATE * damage.amount
157	    : damage.amount;
158	
159	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
160	  const item = policyItems.find((it) => it.type === damage.itemType);
161	  return reimbursableAmount(damage, item) - DEDUCTIBLE;
162	};
163	
164	const assertNonNegativeAmounts = (damages: Damage[]): void => {
165	  for (const damage of damages) {
166	    if (damage.amount < 0) {
167	      throw new Error(`Negative damage amount: ${damage.amount}`);
168	    }
169	  }
170	};
171	
172	const assertDamagesWithinInsuredCounts = (
173	  damages: Damage[],
174	  policyItems: Item[],
175	): void => {
176	  const insuredCounts = countByType(policyItems);
177	  const damageCounts = countBy(damages, (damage) => damage.itemType);
178	  for (const [itemType, count] of damageCounts) {
179	    if (count > (insuredCounts.get(itemType) ?? 0)) {
180	      throw new Error(
181	        `Claim rejected: ${count} ${itemType} damages exceed insured count`,
182	      );
183	    }
184	  }
185	};
186	
187	const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
188	  assertNonNegativeAmounts(damages);
189	  assertDamagesWithinInsuredCounts(damages, policyItems);
190	};
191	
192	const claimResult = (
193	  step: ClaimStep,
194	  policyItems: Item[],
195	  remainingCapBefore: number,
196	): ClaimResult => {
197	  validateDamages(step.incident.damages, policyItems);
198	  const rawPayout = step.incident.damages.reduce(
199	    (sum, damage) => sum + damagePayout(damage, policyItems),
200	    0,
201	  );
202	  const payout = Math.min(Math.floor(rawPayout), remainingCapBefore);
203	  return { payout, remainingCap: remainingCapBefore - payout };
204	};
205	
206	interface Policy {
207	  items: Item[];
208	  remainingCap: number;
209	}
210	
211	const processClaim = (
212	  step: ClaimStep,
213	  policiesByStep: Map<number, Policy>,
214	): ClaimResult => {
215	  const policy = policiesByStep.get(step.policy) ?? { items: [], remainingCap: 0 };
216	  const result = claimResult(step, policy.items, policy.remainingCap);
217	  policy.remainingCap = result.remainingCap;
218	  return result;
219	};
220	
221	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
222	  const policiesByStep = new Map<number, Policy>();
223	  let quoteCount = 0;
224	  const results: StepResult[] = [];
225	  scenario.steps.forEach((step, index) => {
226	    if (step.op === "quote") {
227	      const isFollowup = quoteCount > 0;
228	      results.push({ premium: quotePremium(step.items, scenario.customer, isFollowup) });
229	      policiesByStep.set(index, {
230	        items: step.items,
231	        remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
232	      });
233	      quoteCount += 1;
234	    } else {
235	      results.push(processClaim(step, policiesByStep));
236	    }
237	  });
238	  return { results };
239	};

